     6→import { RescueTypes, rescueActions, ResgateResponse, RescuePayload } from '../../ducks/rescue';
     7→
     8→export function* postRescue({
     9→  data,
    10→}: {
    11→  type: RescueTypes.REQUEST;
    12→  data: {
    13→    payload?: RescuePayload;
    14→    onSuccess?: (status: ResgateResponse['status']) => void;
    15→    onFailed?: (status?: ResgateResponse['status']) => void;
    16→  };
    17→}) {
    18→  try {
    19→    const accessTokenApp = yield storage.getItem('accessToken');
    20→    let participantId = data?.payload?.participantId;
    21→
    22→    if (!participantId && accessTokenApp) {
    23→      const decoded = jwt_decode(accessTokenApp);
    24→      participantId = decoded?.NRC ?? participantId;
    25→    }
    26→
    27→    const payload = {
    28→      ...(data?.payload ?? {}),
    29→      ...(participantId ? { participantId } : {}),
    30→    };
    31→
    32→    const url = 'fintech/v1/rewardProgram/rescue';
    33→
    34→    const response: { data: ResgateResponse } = yield call(
    35→      api.post,
    36→      url,
    37→      payload,
    38→    );
    39→
    40→    const rawStatus =
    41→      response?.data?.status ??
    42→      response?.data?.data?.status
    43→
    44→    if (!rawStatus) {
    45→      yield put(rescueActions.rescueFailed({ status: rawStatus }));
    46→      data?.onFailed?.(rawStatus);
    47→      return;
    48→    }
    49→
    50→    const isSuccess = rawStatus?.message?.toLowerCase() === 'success';
    51→    if (isSuccess) {
    52→
    53→      yield put(rescueActions.rescueSuccess({ status: rawStatus }));
    54→      data?.onSuccess?.(rawStatus);
    55→      return;
    56→    }
    57→
    58→    yield put(rescueActions.rescueFailed({ status: rawStatus }));
    59→    data?.onFailed?.(rawStatus);
    60→
    61→  } catch (error) {
    62→    yield put(rescueActions.rescueFailed({ status: undefined }));
    63→    if (typeof data?.onFailed === 'function') data.onFailed(undefined);
    64→  }
    65→}
