import { put, call } from '@redux-saga/core/effects';
import { api } from '@semparar/mf-app-user';

import { PointsActions } from '../../ducks/points';
import { ParameterizationResponse, ParametrizationData } from './models';

function extractPointsQuantity(parameterization: ParametrizationData[]): number {
  const pointsRescueItem = parameterization?.find(
    item => item.category === 'pointsRescueSentence'
  );

  if (!pointsRescueItem?.value) {
    return 0;
  }

  try {
    let parsedValue = JSON.parse(pointsRescueItem.value);

    if (typeof parsedValue === 'string') {
      parsedValue = JSON.parse(parsedValue);
    }

    if (parsedValue && parsedValue.pointsQuantity !== undefined) {
      const ptsQuantity = Number(parsedValue.pointsQuantity);

      if (!isNaN(ptsQuantity) && ptsQuantity >= 0) {
        return ptsQuantity;
      }
    }

    return 0;
  } catch (error) {
    console.error('Error parsing pointsQuantity:', error);
    return 0;
  }
}

export function* getParameterization() {
  try {
    const response: ParameterizationResponse = yield call(
      api.get,
      'products/v1/pointsProgram/consult-fintech-parameter-points-program',
    );

    const returnCode = response?.data?.serviceMessage?.codigoRetorno;
    const parameterizationData = response?.data?.data;

    if (returnCode === 0) {
      const pointsQuantity = extractPointsQuantity(parameterizationData);

      yield put(PointsActions.successParameterization(
        parameterizationData,
        pointsQuantity,
      ));
    } else {
      yield put(PointsActions.failedParameterization());
    }
  } catch(err) {
    yield put(PointsActions.failedParameterization());
  }
}

import { StateCreator } from 'zustand';

import {
  AirlineMilesSlice,
  createAirlineMilesSlice,
  createMarketplaceSlice,
  createParameterPointsProgramSlice,
  createPermissionSlice,
  createPointsExtractSlice,
  createPointsProductsSlice,
  createRescueSlice,
  MarketplaceSlice,
  ParameterPointsProgramSlice,
  PermissionSlice,
  PointsExtractSlice,
  PointsProductsSlice,
  RescueSlice,
} from '../index';

export type RewardsProgramRootStore = ParameterPointsProgramSlice &
  PermissionSlice &
  AirlineMilesSlice &
  PointsExtractSlice &
  PointsProductsSlice &
  RescueSlice &
  MarketplaceSlice;

type Slice<T> = StateCreator<RewardsProgramRootStore, [], [], T>;
const asSlice = <T>(slice: StateCreator<RewardsProgramRootStore, [], [], T>) =>
  slice as Slice<T>;

export function setRewardsProgramSlices<T extends RewardsProgramRootStore>(
  ...a: Parameters<Slice<T>>
) {
  return {
    ...asSlice<ParameterPointsProgramSlice>(createParameterPointsProgramSlice)(
      ...a,
    ),
    ...asSlice<PermissionSlice>(createPermissionSlice)(...a),
    ...asSlice<AirlineMilesSlice>(createAirlineMilesSlice)(...a),
    ...asSlice<PointsExtractSlice>(createPointsExtractSlice)(...a),
    ...asSlice<PointsProductsSlice>(createPointsProductsSlice)(...a),
    ...asSlice<RescueSlice>(createRescueSlice)(...a),
    ...asSlice<MarketplaceSlice>(createMarketplaceSlice)(...a),
  };
}

